"use client";

import { Suspense, useEffect, useState } from "react";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import { formatINR, getVendor, Vendor } from "../../../lib/vendors";

function VendorContent() {
  const params = useSearchParams(); const router = useRouter(); const slug = params.get("slug");
  const [vendor, setVendor] = useState<Vendor | null>(null); const [error, setError] = useState("");
  useEffect(() => { if (!slug) { setError("Choose a vendor from the marketplace first."); return; } getVendor(slug).then((data) => setVendor(data.vendor)).catch((requestError) => setError(requestError.message || "Vendor not found.")); }, [slug]);
  if (error) return <main className="mx-auto max-w-3xl px-6 py-20"><div role="alert" className="rounded-2xl border border-red-200 bg-red-50 p-6 text-red-900"><h1 className="text-xl font-bold">We could not open this vendor</h1><p className="mt-2">{error}</p><Link href="/services" className="mt-5 inline-block rounded-lg bg-[#8B000F] px-4 py-2 font-semibold text-white">Browse vendors</Link></div></main>;
  if (!vendor) return <main className="mx-auto max-w-6xl px-6 py-12" aria-busy="true"><div className="grid gap-10 md:grid-cols-2"><div className="h-80 animate-pulse rounded-3xl bg-[#f7e9e4]" /><div className="space-y-4"><div className="h-5 w-32 animate-pulse rounded bg-slate-100" /><div className="h-12 w-3/4 animate-pulse rounded bg-slate-100" /><div className="h-24 animate-pulse rounded bg-slate-100" /></div></div></main>;
  const book = (serviceId: number) => router.push(`/customer/checkout?vendor=${encodeURIComponent(vendor.slug)}&service=${serviceId}`);
  return <main className="bg-[#fffdfc] pb-24"><section className="border-b border-[#f2ddd5] bg-[#fff7f3]"><div className="mx-auto max-w-6xl px-6 py-6"><Link href="/services" className="text-sm font-semibold text-[#8B000F] underline underline-offset-4">← Back to vendors</Link></div></section><div className="mx-auto max-w-6xl px-6 py-10"><section className="grid gap-10 md:grid-cols-2"><img src={vendor.avatarUrl || "/weddingpic.jpg"} alt={`${vendor.businessName} cover`} className="h-80 w-full rounded-3xl object-cover shadow-lg" /><div className="flex flex-col items-start"><div className="flex flex-wrap items-center gap-2"><span className="rounded-full bg-[#fff0f3] px-3 py-1 text-sm font-bold text-[#8B000F]">{vendor.category?.name || "Event vendor"}</span>{vendor.approvalStatus === "approved" && <span className="rounded-full bg-emerald-50 px-3 py-1 text-sm font-semibold text-emerald-700">Approved vendor</span>}</div><h1 className="mt-4 font-serif text-4xl font-bold text-[#5c1632]">{vendor.businessName}</h1><p className="mt-3 text-slate-700">{[vendor.city, vendor.state].filter(Boolean).join(", ") || "Bihar"}</p><p className="mt-5 leading-7 text-slate-700">{vendor.description || "This vendor has not added an introduction yet."}</p><p className="mt-6 text-lg font-bold text-[#6b1839]">Starting from {formatINR(vendor.priceFromMinor)}</p>{vendor.services?.length ? <button type="button" onClick={() => book(vendor.services![0].id)} className="mt-7 rounded-xl bg-[#8B000F] px-6 py-3 font-semibold text-white shadow-sm hover:bg-[#6b000f] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#8B000F] focus-visible:ring-offset-2">Request booking</button> : <p className="mt-7 rounded-xl border border-dashed border-[#d9bcb1] p-4 text-sm text-slate-600">Services will appear here when this vendor adds them.</p>}</div></section><section className="mt-16"><h2 className="font-serif text-3xl font-bold text-[#5c1632]">Services and packages</h2><p className="mt-2 text-slate-600">Select a service to start a booking request. Final availability is confirmed by the vendor.</p><div className="mt-6 grid gap-5 md:grid-cols-2">{vendor.services?.map((service) => <article key={service.id} className="rounded-2xl border border-[#f0ded8] bg-white p-6 shadow-sm"><h3 className="text-xl font-bold text-[#6b1839]">{service.name}</h3><p className="mt-3 min-h-12 text-sm leading-6 text-slate-600">{service.description || "Service details will be confirmed by the vendor."}</p><p className="mt-4 font-bold">From {formatINR(service.priceFromMinor)}</p>{service.packages?.map((item) => <div key={item.id} className="mt-3 rounded-xl bg-[#fff7f3] p-3 text-sm"><p className="font-semibold">{item.name} — {formatINR(item.priceMinor)}</p>{item.description && <p className="mt-1 text-slate-600">{item.description}</p>}</div>)}<button type="button" onClick={() => book(service.id)} className="mt-5 rounded-lg border border-[#8B000F] px-4 py-2 text-sm font-semibold text-[#8B000F] hover:bg-[#fff0f3]">Request this service</button></article>)}{!vendor.services?.length && <div className="rounded-2xl border border-dashed border-[#d9bcb1] bg-white p-8 text-slate-600">No services are available yet.</div>}</div></section><section className="mt-16"><h2 className="font-serif text-3xl font-bold text-[#5c1632]">Customer reviews</h2><div className="mt-6 grid gap-4 md:grid-cols-2">{vendor.reviews?.map((review) => <article key={review.id} className="rounded-2xl border border-[#f0ded8] bg-white p-5"><p aria-label={`${review.rating} out of 5 stars`} className="font-semibold text-[#8B000F]">{"★".repeat(review.rating)}<span className="ml-2 text-sm text-slate-700">{review.customerName || "Eventra customer"}</span></p><p className="mt-3 text-slate-700">{review.comment}</p><p className="mt-3 text-xs text-slate-500">{new Date(review.createdAt).toLocaleDateString("en-IN", { dateStyle: "medium" })}</p></article>)}{!vendor.reviews?.length && <p className="rounded-2xl border border-dashed border-[#d9bcb1] bg-white p-6 text-slate-600">No customer reviews have been published yet.</p>}</div></section></div>{vendor.services?.length ? <div className="fixed inset-x-0 bottom-0 border-t border-[#f0ded8] bg-white/95 p-3 backdrop-blur md:hidden"><button type="button" onClick={() => book(vendor.services![0].id)} className="w-full rounded-xl bg-[#8B000F] px-5 py-3 font-semibold text-white">Request booking</button></div> : null}</main>;
}
export default function CustomerVendorPage() { return <Suspense fallback={<main className="p-8">Loading vendor…</main>}><VendorContent /></Suspense>; }
